import { products } from "../data.js";
import type { Product } from "../types.js";
import { NotFoundError, ValidationError } from "./errors.js";

type FilterProductsParams = {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
};

type EnrichedProduct = Product & { isLowStock: boolean; inventoryValue: number };

type ProductListResult = {
  products: Product[];
  summary: { count: number; totalInventoryValue: number; averagePrice: number };
};

export function filterAndSummarize(params: FilterProductsParams): ProductListResult {
  let filtered = [...products];

  if (params.category !== undefined) {
    filtered = filtered.filter((p) => p.category === params.category);
  }

  if (params.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= params.minPrice!);
  }

  if (params.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= params.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getById(id: number): EnrichedProduct {
  const product = products.find((p) => p.id === id);

  if (!product) {
    throw new NotFoundError("Product not found");
  }

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

export function adjustStock(id: number, adjustment: unknown): EnrichedProduct {
  const product = products.find((p) => p.id === id);

  if (!product) {
    throw new NotFoundError("Product not found");
  }

  if (typeof adjustment !== "number") {
    throw new ValidationError("adjustment must be a number");
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    throw new ValidationError("Insufficient stock");
  }

  product.stock = newStock;

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

